m365-347.implementationNotes:
# Audit synced admin accounts
Connect-MgGraph -Scopes 'User.Read.All','RoleManagement.Read.Directory'
$admins = Get-MgDirectoryRoleMember -DirectoryRoleId (Get-MgDirectoryRole -Filter "displayName eq 'Global Administrator'").Id
foreach ($a in $admins) {
  $user = Get-MgUser -UserId $a.Id -Property onPremisesSyncEnabled,userPrincipalName
  if ($user.OnPremisesSyncEnabled) {
    Write-Warning "SYNCED ADMIN: $($user.UserPrincipalName) — must migrate to cloud-only"
  }
}

# Create cloud-only replacement
$params = @{
  AccountEnabled = $true
  DisplayName = 'CloudAdmin-Emergency'
  MailNickname = 'cloudadmin'
  UserPrincipalName = 'cloudadmin@yourdomain.onmicrosoft.com'
  PasswordProfile = @{ ForceChangePasswordNextSignIn = $true; Password = (New-Guid).ToString() }
}
New-MgUser @params

m365-347.validationNotes:
# Verify no synced accounts hold admin roles
Get-MgDirectoryRoleMember -DirectoryRoleId (Get-MgDirectoryRole -Filter "displayName eq 'Global Administrator'").Id | ForEach-Object {
  Get-MgUser -UserId $_.Id -Property onPremisesSyncEnabled,userPrincipalName
} | Where-Object { $_.OnPremisesSyncEnabled -eq $true } | Measure-Object
# Expected: Count = 0

m365-348.implementationNotes:
# Create two emergency access accounts
$domains = Get-MgDomain | Where-Object { $_.IsInitial -eq $true }
$domain = $domains[0].Id

foreach ($i in 1..2) {
  $upn = "BreakGlass$i@$domain"
  $params = @{
    AccountEnabled = $true
    DisplayName = "Emergency Access $i"
    MailNickname = "breakglass$i"
    UserPrincipalName = $upn
    PasswordProfile = @{
      ForceChangePasswordNextSignIn = $false
      Password = [System.Web.Security.Membership]::GeneratePassword(24,6)
    }
  }
  $user = New-MgUser @params
  # Assign Global Admin
  $role = Get-MgDirectoryRole -Filter "displayName eq 'Global Administrator'"
  New-MgDirectoryRoleMember -DirectoryRoleId $role.Id -BodyParameter @{ '@odata.id' = "https://graph.microsoft.com/v1.0/directoryObjects/$($user.Id)" }
  Write-Host "Created $upn — store credentials in physical safe"
}

m365-348.validationNotes:
# Verify break-glass accounts exist and have Global Admin
$role = Get-MgDirectoryRole -Filter "displayName eq 'Global Administrator'"
Get-MgDirectoryRoleMember -DirectoryRoleId $role.Id | ForEach-Object {
  Get-MgUser -UserId $_.Id -Property displayName,userPrincipalName
} | Where-Object { $_.DisplayName -like '*Emergency*' -or $_.DisplayName -like '*BreakGlass*' }
# Expected: 2 accounts

# Verify excluded from Conditional Access
Get-MgIdentityConditionalAccessPolicy | ForEach-Object {
  $_.Conditions.Users.ExcludeUsers
}

m365-349.validationNotes:
# Verify count is between 2 and 4 (excluding break-glass)
$gaRole = Get-MgDirectoryRole -Filter "displayName eq 'Global Administrator'"
$count = (Get-MgDirectoryRoleMember -DirectoryRoleId $gaRole.Id | Measure-Object).Count
if ($count -lt 2 -or $count -gt 4) {
  Write-Warning "Global Admin count is $count — should be 2-4 (plus break-glass)"
} else {
  Write-Host "OK: $count Global Admins" -ForegroundColor Green
}
